import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as d,o as c,c as t,a as e,b as a,d as l,e as o}from"./app-be253e4c.js";const n={},s=o('<h1 id="分布式消息中间件实践" tabindex="-1"><a class="header-anchor" href="#分布式消息中间件实践" aria-hidden="true">#</a> 分布式消息中间件实践</h1><h2 id="消息队列" tabindex="-1"><a class="header-anchor" href="#消息队列" aria-hidden="true">#</a> 消息队列</h2><p><code>中间件</code>：非底层操作系统软件、非业务应用软件，不是直接给最终用户使用的，不能直接带来价值的软件统称为<strong>中间件</strong></p><h2 id="消息协议" tabindex="-1"><a class="header-anchor" href="#消息协议" aria-hidden="true">#</a> 消息协议</h2><p><code>协议</code>：计算机术语中的协议，就是一个达成一致的并受规则支配的交互集合，例如计算机网络中的七层网络协议，http协议等-----&gt; protocol</p><blockquote><p>计算机领域中 ，只要涉及不同计算机之间要共同完成一件事情的时候，就肯定会有协议的存在，就好比我们说话、沟通用某种语言一样，不用的计算机之间必须要使用相同的语言才能够正常通信、交流</p></blockquote><p><code>消息协议</code>：用于实现消息队列功能时所涉及的协议。</p><p>按照是否向行业开放消息规范文档，可以将消息分为：</p><ul><li>开发协议（AMQP、MQTT、STOMP、XMPP等）</li><li>私有协议</li></ul><p>有些特殊框架（例如：Redis、Kafka、ZeroMQ）更具自身需要未严格遵循MQ规范，而是基于<code>TCP/IP</code>封装的一套协议，通过网络Socket接口进行传输，实现了MQ功能。【这里的协议可以理解为双方通信的一个约定】</p><h3 id="amqp协议" tabindex="-1"><a class="header-anchor" href="#amqp协议" aria-hidden="true">#</a> AMQP协议</h3>',11),h={href:"https://baike.baidu.com/item/AMQP/8354716?fr=aladdin",target:"_blank",rel:"noopener noreferrer"},p=o('<p>目前AMQP协议的版本是用两个或者三个数字表示的，格式为：<code>major-minor[-revision]</code>或<code>major.minor[.revision]</code>，其中：</p><ul><li>major：主版本号</li><li>minor：次版本号</li><li>revision：可选的修订版本号</li></ul><p>都是可以用0~99之间的一个数字表示，<strong>100以上的数字都被保留下来了，用于内部测试和开发</strong></p><p>例如：</p><ul><li>RabbitMQ支持<code>AMQP 0-9-1</code> 协议</li><li>ActiveMQ、Apollo、Qpid支持<code>AMQP 0-9-10</code> 协议</li></ul><p>一般来说，将AMQP分为三个部分：</p><ul><li><code>基础概念</code>：内部定义的各组件及组件的功能说明</li><li>`功能命令：协议所定义的一系列的命令，应用程序可以基于这些命令来实现相应的功能。</li><li><code>传输层协议</code>：网络级协议，定义了数据的传输格式，消息队列的客户端可以基于这个协议与消息代理和AMQP的相关模型进行交互通信【包括：数据帧处理、信道复用、内容编码、心跳检测、数据表示和错误处理等。】</li></ul><h3 id="基础概念" tabindex="-1"><a class="header-anchor" href="#基础概念" aria-hidden="true">#</a> 基础概念</h3><h4 id="核心组件的声明周期" tabindex="-1"><a class="header-anchor" href="#核心组件的声明周期" aria-hidden="true">#</a> 核心组件的声明周期</h4>',9);function u(m,_){const r=d("ExternalLinkIcon");return c(),t("div",null,[s,e("blockquote",null,[e("p",null,[a("AMQP，即Advanced Message Queuing Protocol，一个提供统一消息服务的应用层标准高级消息队列协议，是应用层协议的一个开放标准，为面向消息的中间件设计。基于此协议的客户端与消息中间件可传递消息，并不受客户端/中间件不同产品，不同的开发语言等条件的限制。Erlang中的实现有RabbitMQ等。"),e("a",h,[a("百度百科"),l(r)])])]),p])}const Q=i(n,[["render",u],["__file","middleware-practice.html.vue"]]);export{Q as default};
